const msg = $input.first().json.message;
const text = (msg.text || '').trim();
const chatId = msg.chat.id;
const telegramId = msg.from.id;
const firstName = msg.from.first_name || '';
const username = msg.from.username || '';

// Helper: escape single quotes for SQL
const esc = (s) => (s || '').replace(/'/g, "''");

// ---- Classify intent ----
let intent = 'unknown';
const lower = text.toLowerCase();

if (/^\/?(?:start|help)$/i.test(text)) {
  intent = 'help';
} else if (/\b(delete\s*last|remove\s*last|undo|cancel\s*last)\b/i.test(text)) {
  intent = 'delete_last';
} else if (/\b(edit\s*last|change\s*last|correct\s*last|last\s*was)\b/i.test(text)) {
  intent = 'edit_last';
} else if (/\d/.test(text)) {
  intent = 'log_expense';
}

// ---- Parse for log_expense ----
let amount = 0;
let category = 'Misc';
let note = '';
let tags = [];
let tagsLiteral = '{}';
let dateOffset = 0;

// ---- Detect date references ----
const yesterdayMatch = lower.match(/\byesterday\b/);
const daysAgoMatch = lower.match(/(\d+)\s*days?\s*ago/);
if (yesterdayMatch) {
  dateOffset = 1;
} else if (daysAgoMatch) {
  dateOffset = parseInt(daysAgoMatch[1], 10);
}

if (intent === 'log_expense') {
  const numMatch = text.match(/\d+(?:\.\d{1,2})?/);
  amount = numMatch ? parseFloat(numMatch[0]) : 0;

  const tagMatches = text.match(/#\w+/g);
  if (tagMatches) {
    tags = tagMatches;
    tagsLiteral = '{' + tagMatches.map(t => '"' + t + '"').join(',') + '}';
  }

  let cleaned = text
    .replace(/\byesterday\b/gi, '')
    .replace(/\d+\s*days?\s*ago/gi, '')
    .replace(/\d+(?:\.\d{1,2})?/g, '')
    .replace(/#\w+/g, '')
    .replace(/\b(spent|on|for|rs|npr|rupees|rp|paid)\b/gi, '')
    .replace(/\s+/g, ' ')
    .trim();

  const catMap = {
    'Food': ['food','lunch','dinner','breakfast','snack','meal','restaurant','cafe','chai','tea','coffee','momo','dal bhat','tiffin','canteen'],
    'Transport': ['petrol','diesel','fuel','uber','taxi','bus','bike','ride','fare','auto','grab','ola','pathao'],
    'Groceries': ['groceries','grocery','vegetables','fruits','supermarket','bhatbhateni','bigmart','dairy','milk','eggs'],
    'Rent': ['rent','house rent','room rent','flat'],
    'Utilities': ['electricity','water','internet','wifi','phone','mobile','recharge','bill','nea','ntc','ncell'],
    'Entertainment': ['movie','netflix','spotify','game','party','outing','drinks','beer'],
    'Health': ['medicine','doctor','hospital','pharmacy','gym','medical','health','dental'],
    'Shopping': ['clothes','shoes','electronics','amazon','daraz','gadget','laptop'],
    'Subscriptions': ['subscription','premium','membership','annual','monthly plan'],
    'Education': ['books','course','tuition','class','training','udemy','coursera']
  };

  let matchedKw = '';
  const lowerCleaned = cleaned.toLowerCase();
  for (const [cat, kws] of Object.entries(catMap)) {
    for (const kw of kws) {
      if (lowerCleaned.includes(kw) && kw.length > matchedKw.length) {
        category = cat;
        matchedKw = kw;
      }
    }
  }

  if (matchedKw) {
    const idx = lowerCleaned.indexOf(matchedKw);
    note = (cleaned.substring(0, idx) + cleaned.substring(idx + matchedKw.length)).replace(/\s+/g, ' ').trim();
  } else {
    note = cleaned;
  }
}

// ---- Parse for edit_last ----
let editAmount = null;
let editCategory = null;
let editQuery = '';

if (intent === 'edit_last') {
  const amtMatch = text.match(/(?:amount\s*(?:to\s*)?|to\s+)(\d+(?:\.\d{1,2})?)/i);
  if (amtMatch) editAmount = parseFloat(amtMatch[1]);

  const catMatch = text.match(/(?:was|to)\s+(\w+)/i);
  if (catMatch) {
    const possibleCat = catMatch[1].toLowerCase();
    const allCats = ['food','transport','groceries','rent','utilities','entertainment','health','shopping','subscriptions','education','misc'];
    if (allCats.includes(possibleCat)) {
      editCategory = possibleCat.charAt(0).toUpperCase() + possibleCat.slice(1);
    }
  }

  if (!editAmount && !editCategory) {
    const numMatch = text.match(/\d+(?:\.\d{1,2})?/);
    if (numMatch) editAmount = parseFloat(numMatch[0]);
  }

  if (editAmount === null && editCategory === null) {
    editQuery = "SELECT 'no_edit' AS result;";
  } else {
    const setClauses = [];
    if (editAmount !== null) setClauses.push('amount = ' + editAmount);
    if (editCategory !== null) setClauses.push("category = '" + esc(editCategory) + "'");
    setClauses.push('updated_at = NOW()');

    editQuery = "WITH usr AS (" +
      " INSERT INTO users (telegram_id, display_name, telegram_username)" +
      " VALUES (" + telegramId + ", '" + esc(firstName) + "', '" + esc(username) + "')" +
      " ON CONFLICT (telegram_id) DO UPDATE SET display_name = EXCLUDED.display_name" +
      " RETURNING id" +
      "), old_vals AS (" +
      " SELECT id, amount AS old_amount, category AS old_category" +
      " FROM transactions" +
      " WHERE user_id = (SELECT id FROM usr) AND status = 'active'" +
      " ORDER BY created_at DESC LIMIT 1" +
      "), updated AS (" +
      " UPDATE transactions SET " + setClauses.join(', ') +
      " WHERE id = (SELECT id FROM old_vals)" +
      " RETURNING transactions.id, transactions.amount, transactions.category, transactions.date" +
      ") SELECT" +
      " COALESCE(u.id, 'NONE') AS id," +
      " COALESCE(u.amount, 0) AS amount," +
      " COALESCE(u.category, '') AS category," +
      " u.date," +
      " COALESCE(o.old_amount, 0) AS old_amount," +
      " COALESCE(o.old_category, '') AS old_category," +
      " CASE WHEN u.id IS NOT NULL THEN 'updated' ELSE 'not_found' END AS result" +
      " FROM (SELECT 1) AS dummy" +
      " LEFT JOIN updated u ON true" +
      " LEFT JOIN old_vals o ON true;";
  }
}

return [{
  json: {
    chatId,
    telegramId,
    firstName: esc(firstName),
    username: esc(username),
    originalMessage: esc(text),
    intent,
    amount,
    category,
    note: esc(note),
    tagsLiteral,
    dateOffset,
    editAmount,
    editCategory,
    editQuery
  }
}];

const txn = $input.first().json;
const chatId = $('Parse Message').first().json.chatId;
const dateObj = new Date(txn.date);
const dateStr = dateObj.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
const timeStr = txn.time ? txn.time.substring(0, 5) : '';

let reply = '✅ Logged: NPR ' + Number(txn.amount).toLocaleString() + ' → ' + txn.category + '\n';
reply += '📅 ' + dateStr + ' | ' + timeStr + '\n';
reply += '🆔 ' + txn.id;
if (txn.note) reply += '\n📝 ' + txn.note;

return [{ json: { chatId, reply } }];

const row = $input.first().json;
const chatId = $('Parse Message').first().json.chatId;
let reply;

if (row.result === 'not_found') {
  reply = '❌ No active transaction found to delete.';
} else {
  const dateStr = row.date ? new Date(row.date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' }) : '';
  reply = '🗑 Deleted: NPR ' + Number(row.amount).toLocaleString() + ' → ' + row.category + ' (' + dateStr + ')\n🆔 ' + row.id;
}

return [{ json: { chatId, reply } }];

const row = $input.first().json;
const chatId = $('Parse Message').first().json.chatId;
let reply;

if (row.result === 'no_edit') {
  reply = '❌ Could not understand what to edit.\n\nTry:\n• edit last amount to 150\n• last was transport not food';
} else if (row.result === 'not_found' || !row.id || row.id === 'NONE') {
  reply = '❌ No active transaction found to edit.';
} else {
  const changes = [];
  if (Number(row.old_amount) !== Number(row.amount)) {
    changes.push('Amount: NPR ' + Number(row.old_amount).toLocaleString() + ' → NPR ' + Number(row.amount).toLocaleString());
  }
  if (row.old_category !== row.category) {
    changes.push('Category: ' + row.old_category + ' → ' + row.category);
  }
  reply = '✏️ Updated: ' + row.id + '\n' + changes.join('\n');
}

return [{ json: { chatId, reply } }];
